<div class="en">
<svg viewBox="0 0 700 380" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Anatomy of the Jul 10 Solana Genesis Wallet Theft</text>
  <g font-family="sans-serif">
    <rect x="20" y="55" width="150" height="70" rx="10" fill="#1c1c1f" stroke="#3f3f46" stroke-width="1.2"/>
